const upd = $input.first().json;
let chatId, text;

if (upd.callback_query) {
  chatId = upd.callback_query.message.chat.id;
  text = upd.callback_query.data;
} else if (upd.message) {
  chatId = upd.message.chat.id;
  text = (upd.message.text || '').trim();
} else {
  return [];
}

return [{ json: { sessionId: String(chatId), chatId: String(chatId), text } }];

const query = ($input.first().json.query || '').toString().trim();

function normalize(str) {
  return String(str || '')
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-z0-9\s]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

const url = 'https://docs.google.com/spreadsheets/d/1G8wEi3bOLxzFKzm086op_tkvciQ7ZTA4METm4pP_g30/gviz/tq?tqx=out:json&gid=427774701';

let data;
try {
  const res = await $helpers.httpRequest({ method: 'GET', url, returnFullResponse: true });
  const text = typeof res === 'string' ? res : (res.body || JSON.stringify(res));
  const jsonStr = text.replace(/^[^(]+\(/, '').replace(/\);?\s*$/, '');
  data = JSON.parse(jsonStr);
} catch(e) {
  return [{ json: { response: '⚠️ Error al conectar con el inventario: ' + e.message } }];
}

const cols = data.table.cols.map(c => (c.label || c.id || '').trim());
const rows = (data.table.rows || [])
  .map(row => {
    const obj = {};
    (row.c || []).forEach((cell, i) => {
      if (cols[i]) obj[cols[i]] = cell && cell.v !== null ? cell.v : '';
    });
    return obj;
  })
  .filter(r => r['Material']);

const normQuery = normalize(query);
const tokens = normQuery.split(' ').filter(t => t.length >= 2);

if (tokens.length === 0) {
  return [{ json: { response: '❓ ¿Qué producto buscas? Indica el nombre, tipo o código.' } }];
}

const scored = rows.map(row => {
  const combined = normalize(String(row['Material'])) + ' ' + normalize(String(row['Texto breve de material'] || ''));
  const hits = tokens.filter(t => combined.includes(t)).length;
  return { row, hits };
}).filter(r => r.hits > 0).sort((a, b) => b.hits - a.hits);

if (scored.length === 0) {
  return [{ json: { response: `❌ No encontré productos con "${query}".\nIntenta con otro término: tipo, diámetro o código del producto.` } }];
}

const exact = scored.filter(r => r.hits === tokens.length);
const candidates = exact.length > 0 ? exact : scored;

if (candidates.length > 8) {
  return [{ json: { response: `🔍 "${query}" tiene ${candidates.length} resultados. ¿Puedes ser más específico? Indica diámetro, tipo de tubería o código.` } }];
}

const lines = candidates.slice(0, 8).map(r => {
  const d = r.row;
  const dispRaw = String(d['Inven Disp Unid'] || '0').trim();
  const dispNum = parseFloat(dispRaw.replace(/\./g, '').replace(',', '.')) || 0;
  const boRaw = String(d['Unid Backorder Total'] || '0').trim();
  const boNum = parseFloat(boRaw.replace(/\./g, '').replace(',', '.')) || 0;
  const stockIcon = dispNum > 0 ? '✅' : '❌';
  const bo = boNum > 0 ? ` | BO: ${boRaw} uds` : '';
  return `${d['Material']} | ${d['Texto breve de material']}\n  ${stockIcon} Disp: ${dispRaw} uds${bo}`;
});

return [{ json: { response: `📦 "${query}" — ${candidates.length} resultado(s):\n\n${lines.join('\n\n')}` } }];

